// server/utils/crypto.ts
import crypto4 from "crypto";
function generatePrefixedApiKey() {
  const prefix = "il_";
  const randomBytes = crypto4.randomBytes(16);
  const randomString = randomBytes.toString("hex");
  return prefix + randomString;
}
function isValidApiKeyFormat(key) {
  return /^il_[a-f0-9]{32}$/.test(key);
}

// server/middleware/api-key-auth.ts
init_storage();
async function verifyApiKey(req, res, next) {
  try {
    const apiKey = req.headers["x-api-key"];
    if (!apiKey) {
      return res.status(401).json({
        error: "API key required. Include it in the x-api-key header."
      });
    }
    if (!isValidApiKeyFormat(apiKey)) {
      return res.status(401).json({
        error: "Invalid API key format."
      });
    }
    const keyRecord = await getApiKeyByKey(apiKey);
    if (!keyRecord) {
      return res.status(401).json({
        error: "Invalid API key."
      });
    }
    if (!keyRecord.active) {
      return res.status(401).json({
        error: "API key has been revoked."
      });
    }
    req.apiKey = keyRecord;
    next();
  } catch (error) {
    console.error("API key verification error:", error);
    res.status(500).json({
      error: "Internal server error during API key verification."
    });
  }
}

