import bcrypt6 from "bcryptjs";
import multer from "multer";

// server/services/imageUpload.ts
init_supabase();
var BUCKET_NAME = "islandloaf-images";
async function uploadImage(buffer, filename, mimeType, folder = "services") {
  if (!isSupabaseConfigured()) {
    return { success: false, error: "Supabase is not configured" };
  }
  try {
    const supabase2 = getSupabaseAdmin();
    const ext = filename.split(".").pop() || "jpg";
    const uniqueFilename = `${folder}/${Date.now()}-${Math.random().toString(36).substring(7)}.${ext}`;
    const { data, error } = await supabase2.storage.from(BUCKET_NAME).upload(uniqueFilename, buffer, {
      contentType: mimeType,
      upsert: false
    });
    if (error) {
      console.error("Supabase upload error:", error);
      return { success: false, error: error.message };
    }
    const { data: urlData } = supabase2.storage.from(BUCKET_NAME).getPublicUrl(data.path);
    return {
      success: true,
      url: urlData.publicUrl
    };
  } catch (err) {
    console.error("Image upload error:", err);
    return { success: false, error: err.message };
  }
}
async function ensureBucketExists() {
  if (!isSupabaseConfigured()) {
    console.warn("Supabase not configured, skipping bucket creation");
    return false;
  }
  try {
    const supabase2 = getSupabaseAdmin();
    const { data: buckets } = await supabase2.storage.listBuckets();
    const bucketExists = buckets?.some((b) => b.name === BUCKET_NAME);
    if (!bucketExists) {
      const { error } = await supabase2.storage.createBucket(BUCKET_NAME, {
        public: true,
        fileSizeLimit: 10485760,
        // 10MB
        allowedMimeTypes: ["image/jpeg", "image/png", "image/gif", "image/webp"]
      });
      if (error) {
        console.error("Failed to create bucket:", error);
        return false;
      }
      console.log(`Created storage bucket: ${BUCKET_NAME}`);
    }
    return true;
  } catch (err) {
    console.error("Bucket check error:", err);
    return false;
  }
}

