  app2.get("/api/business/reports", async (req, res) => {
    try {
      const users3 = await getUsers();
      const allBookings = [];
      for (const user of users3) {
        const userBookings = await getBookings(user.id);
        allBookings.push(...userBookings);
      }
      const dailyReports = {};
      allBookings.forEach((booking) => {
        const date2 = new Date(booking.createdAt).toISOString().split("T")[0];
        if (!dailyReports[date2]) {
          dailyReports[date2] = {
            date: date2,
            totalBookings: 0,
            totalRevenue: 0,
            completedBookings: 0,
            cancelledBookings: 0
          };
        }
        dailyReports[date2].totalBookings++;
        dailyReports[date2].totalRevenue += Number(booking.totalPrice) || 0;
        if (booking.status === "completed") {
          dailyReports[date2].completedBookings++;
        } else if (booking.status === "cancelled") {
          dailyReports[date2].cancelledBookings++;
        }
      });
      const reportData = Object.values(dailyReports).sort(
        (a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()
      );
      res.json({
        success: true,
        data: reportData,
        count: reportData.length
      });
    } catch (error) {
      res.status(500).json({
        success: false,
        error: error instanceof Error ? error.message : "Failed to fetch reports"
      });
    }
  });
